#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

struct Item {
    std::string name;
    int value;
    int weight;
};

int main() {
    std::cout << "=== std::vector — Dynamic Inventory ===" << std::endl;

    // 1. Creating a vector
    std::cout << "\n--- Creating vectors ---" << std::endl;
    std::vector<int> scores;  // Empty vector
    std::vector<std::string> names = {"Hero", "Aragorn", "Gandalf"};
    std::vector<int> health(5, 100);  // 5 elements, all 100

    std::cout << "scores size: " << scores.size() << std::endl;
    std::cout << "names size: " << names.size() << std::endl;
    std::cout << "health size: " << health.size() << std::endl;

    // 2. Adding elements
    std::cout << "\n--- Adding elements ---" << std::endl;
    scores.push_back(10);
    scores.push_back(20);
    scores.push_back(30);
    scores.push_back(40);

    std::cout << "After push_back: ";
    for (int s : scores) {
        std::cout << s << " ";
    }
    std::cout << std::endl;

    // 3. Accessing elements
    std::cout << "\n--- Accessing elements ---" << std::endl;
    std::cout << "scores[0]: " << scores[0] << std::endl;
    std::cout << "scores.at(1): " << scores.at(1) << std::endl;
    std::cout << "scores.front(): " << scores.front() << std::endl;
    std::cout << "scores.back(): " << scores.back() << std::endl;

    // 4. Modifying elements
    std::cout << "\n--- Modifying elements ---" << std::endl;
    scores[0] = 99;
    scores.at(2) = 100;
    std::cout << "After modifications: ";
    for (int s : scores) {
        std::cout << s << " ";
    }
    std::cout << std::endl;

    // 5. Removing elements
    std::cout << "\n--- Removing elements ---" << std::endl;
    scores.pop_back();  // Remove last
    std::cout << "After pop_back: ";
    for (int s : scores) {
        std::cout << s << " ";
    }
    std::cout << std::endl;

    // 6. Vector of structs
    std::cout << "\n--- Inventory (vector of Items) ---" << std::endl;
    std::vector<Item> inventory;
    inventory.push_back({"Iron Sword", 50, 3});
    inventory.push_back({"Health Potion", 25, 1});
    inventory.push_back({"Steel Shield", 40, 5});

    for (const Item& item : inventory) {
        std::cout << item.name << " (Value: " << item.value 
                  << ", Weight: " << item.weight << ")" << std::endl;
    }

    // 7. Capacity and size
    std::cout << "\n--- Capacity vs Size ---" << std::endl;
    std::cout << "scores size: " << scores.size() << std::endl;
    std::cout << "scores capacity: " << scores.capacity() << std::endl;

    // 8. Clear and empty
    scores.clear();
    std::cout << "After clear, size: " << scores.size() << std::endl;
    std::cout << "Is empty? " << (scores.empty() ? "Yes" : "No") << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <vector>

int main() {
    std::vector<int> numbers = {1, 2, 3, 4, 5};

    // Modifying while iterating!
    for (size_t i = 0; i < numbers.size(); i++) {
        if (numbers[i] == 3) {
            numbers.erase(numbers.begin() + i);  // Size changes!
        }
    }

    for (int n : numbers) {
        std::cout << n << " ";
    }

    return 0;
}

phase2.explanation:
When you erase from a vector while iterating, the size changes and you skip elements!

**What's happening:**
1. `i=2`, numbers[2] == 3 → erase it
2. Vector becomes [1, 2, 4, 5]
3. `i=3`, numbers[3] == 5 → we skipped 4!

**The fix (Method 1 — reverse loop):**
```cpp
for (int i = numbers.size() - 1; i >= 0; i--) {
    if (numbers[i] == 3) {
        numbers.erase(numbers.begin() + i);
    }
}
```

**The fix (Method 2 — erase-remove idiom):**
```cpp
numbers.erase(
    std::remove(numbers.begin(), numbers.end(), 3),
    numbers.end()
);
```

**PlusPlus-chan says:**
"When erasing from a vector, remember: the size changes. Use reverse iteration or the erase-remove idiom."

phase3.solution:
#include <iostream>
#include <vector>

int main() {
    std::vector<int> scores;

    scores.push_back(10);
    scores.push_back(20);
    scores.push_back(30);
    scores.push_back(40);
    scores.push_back(50);

    std::cout << "Initial scores (size: " << scores.size() << "): ";
    for (int s : scores) {
        std::cout << s << " ";
    }
    std::cout << std::endl;

    scores[0] = 99;
    scores.back() = 80;
    scores.push_back(60);
    scores.pop_back();

    std::cout << "Final scores (size: " << scores.size() << "): ";
    for (int s : scores) {
        std::cout << s << " ";
    }
    std::cout << std::endl;

    return 0;
}
